import io
import re
import pandas as pd
import boto3
from botocore import UNSIGNED
from botocore.client import Config

source = 'datagov/2023-farm-tour/files/rows.txt'
bucket = 'lakeqa-yc4103-datalake'
obj = boto3.client('s3', region_name='us-east-1', config=Config(signature_version=UNSIGNED)).get_object(Bucket=bucket, Key=source)
df = pd.read_csv(io.BytesIO(obj['Body'].read()), dtype=str, usecols=['Farm', 'Saturday and Sunday', 'Animals', 'Location'], low_memory=False)

def clean_city(city):
    city = re.sub(r'\bMD\b', ' ', str(city), flags=re.I)
    city = re.sub(r'\b\d{5}(?:-\d{4})?\b', ' ', city)
    city = re.sub(r"[^A-Za-z .'-]", ' ', city)
    return ' '.join(city.split()).upper()

def parse_city(location):
    text = str(location).replace('\r', '\n')
    lines = [line.strip() for line in text.split('\n') if line.strip()]
    tail = lines[-1] if lines else text.strip()
    candidates = [tail]
    parts = re.split(r'\s{2,}', tail)
    if len(parts) > 1:
        candidates.append(parts[-1])
    for candidate in candidates:
        match = re.match(r"^([A-Za-z .'-]+),?\s+(?:MD\s+)?\d{5}(?:-\d{4})?$", candidate, flags=re.I)
        if match:
            return clean_city(match.group(1))
    match = re.search(r",\s*([A-Za-z .'-]+)\s*,?\s+MD\s+\d{5}(?:-\d{4})?", text, flags=re.I)
    if match:
        return clean_city(match.group(1))
    match = re.search(r",\s*([A-Za-z .'-]+)\s+\d{5}(?:-\d{4})?", text, flags=re.I)
    if match:
        return clean_city(match.group(1))
    match = re.search(r".*\b(?:Rd|Road|St|Street|Ave|Avenue|Dr|Drive|Ln|Lane|Cir|Circle)\.?\s+([A-Za-z .'-]+),\s*\d{5}", text, flags=re.I | re.S)
    if match:
        return clean_city(match.group(1))
    return clean_city(tail)

filtered = df[
    df['Saturday and Sunday'].astype(str).str.strip().str.casefold().eq('true')
    & df['Animals'].astype(str).str.strip().str.casefold().eq('true')
].copy()
filtered['city'] = filtered['Location'].map(parse_city)
counts = filtered['city'].dropna().value_counts()
answer = str(counts.idxmax()).title()
